import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function detectOracleManipulation(chainName, oracleAddress) {
  const events = await client.BaseService.getLogEventsByAddress(
    chainName, oracleAddress, { startingBlock: "latest" }
  );
  const priceUpdates = (events.data?.items ?? []).filter(
    e => e.decoded?.name === "AnswerUpdated" || e.decoded?.name === "PriceUpdated"
  );
  // Flag if price changes >5% between consecutive updates
  const anomalies = priceUpdates.filter((e, i) => {
    if (i === 0) return false;
    const prev = Number(priceUpdates[i - 1]?.decoded?.params?.[0]?.value ?? 1);
    const curr = Number(e.decoded?.params?.[0]?.value ?? 1);
    return Math.abs((curr - prev) / prev) > 0.05;
  });
  return { oracleAddress, anomalyCount: anomalies.length, anomalies };
}
